const change = $json.entry[0].changes[0].value;
const msg = change.messages?.[0];
const contact = change.contacts?.[0];

if (!msg) {
  return [];
}

const from = msg.from;  // phone
const type = msg.type;  // "text", "location", "button", etc.

let text = '';
let buttonPayload = '';
let latitude = null;
let longitude = null;

if (type === 'text') {
  text = msg.text?.body || '';
}

if (type === 'button') {
  buttonPayload = msg.button?.payload || '';
}

if (type === 'location') {
  latitude = msg.location?.latitude || null;
  longitude = msg.location?.longitude || null;
}

return [{
  from,
  type,
  text,
  buttonPayload,
  latitude,
  longitude,
}];

// Get data
const userData = $('Parse SOS Message').first().json;
const addressData = $('Get Address').first().json;
const hospitalsData = $input.first().json;

// Extract address
const address = addressData.display_name || `${userData.latitude}, ${userData.longitude}`;
const city = addressData.address?.city || addressData.address?.town || 'Unknown';
const state = addressData.address?.state || '';
const landmark = addressData.address?.road || addressData.address?.suburb || '';

// Extract and process hospitals
const hospitals = hospitalsData.elements || [];

const hospitalsWithDistance = hospitals.map(hospital => {
  const lat = hospital.lat || hospital.center?.lat;
  const lon = hospital.lon || hospital.center?.lon;

  // Calculate distance
  const R = 6371;
  const dLat = (lat - userData.latitude) * Math.PI / 180;
  const dLon = (lon - userData.longitude) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(userData.latitude * Math.PI / 180) * Math.cos(lat * Math.PI / 180) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  const distance = R * c;

  return {
    name: hospital.tags?.name || 'Hospital',
    phone: hospital.tags?.phone || hospital.tags?.['contact:phone'] || null,
    address: hospital.tags?.['addr:full'] || hospital.tags?.['addr:street'] || 'Address N/A',
    lat: lat,
    lon: lon,
    distance: distance.toFixed(2)
  };
}).filter(h => h.phone) // Only hospitals with phone numbers
  .sort((a, b) => parseFloat(a.distance) - parseFloat(b.distance))
  .slice(0, 5);

return {
  json: {
    userName: userData.userName,
    phoneNumber: userData.phoneNumber,
    latitude: userData.latitude,
    longitude: userData.longitude,
    address: address,
    city: city,
    state: state,
    landmark: landmark,
    hospitals: hospitalsWithDistance,
    hospitalCount: hospitalsWithDistance.length,
    timestamp: userData.timestamp
  }
};

