let from = '';
let type = 'text';
let text = '';
let buttonPayload = '';
let latitude = null;
let longitude = null;

// ✅ Case 1: Real WhatsApp Webhook
if ($json.entry && $json.entry[0]?.changes) {
  const msg = $json.entry[0].changes[0].value.messages[0];

  from = msg.from;
  type = msg.type;
  text = msg.text?.body || '';
  buttonPayload = msg.button?.payload || '';
  latitude = msg.location?.latitude || null;
  longitude = msg.location?.longitude || null;

// ✅ Case 2: n8n Chat Trigger (Testing)
} else {
  text =
    $json.text ||
    $json.chatInput ||
    $json.message ||
    '';

  from = $json.userId || $json.chatId || 'test-user';
  type = 'text';
}

// ✅ FINAL RETURN (VERY IMPORTANT)
return [{
  from,
  phoneNumber: from,     // ✅ REQUIRED for WhatsApp + Twilio + DB
  userName: 'User',      // ✅ Required for voice call script
  type,
  text,
  buttonPayload,
  latitude,
  longitude,
}];

return [{
  whatsappBody: {
    messaging_product: "whatsapp",
    to: $json.phoneNumber || $json.from,
    type: "text",
    text: {
      body: "Please share your live location now 📍"
    }
  }
}];

// Merge hospitals from Google with phone numbers from database
const googleHospitals = $('Process Hospital Data1').first().json.hospitals;
const dbHospitals = $input.all().map(item => item.json);
const userData = $('Process Hospital Data1').first().json;
const sosRecordId = $('Save SOS Record').first().json.id;

// Create merged list with phone numbers
const hospitalsWithPhones = dbHospitals.map(dbHospital => {
  // Find matching hospital from Google results
  const matchingGoogle = googleHospitals.find(gh => 
    gh.name.toLowerCase().includes(dbHospital.hospital_name.toLowerCase()) ||
    dbHospital.hospital_name.toLowerCase().includes(gh.name.toLowerCase())
  );

  return {
    name: dbHospital.hospital_name,
    phone: dbHospital.phone,
    address: dbHospital.address,
    latitude: dbHospital.latitude,
    longitude: dbHospital.longitude,
    distance: matchingGoogle?.distance || 'N/A'
  };
}).filter(h => h.phone); // Only hospitals with phone numbers

if (hospitalsWithPhones.length === 0) {
  return [{
    json: {
      ...userData,
      sosRecordId: sosRecordId,
      noPhoneNumbers: true,
      hospitals: googleHospitals
    }
  }];
}

return [{
  json: {
    ...userData,
    hospitals: hospitalsWithPhones,
    hospitalCount: hospitalsWithPhones.length,
    currentHospitalIndex: 0,
    sosRecordId: sosRecordId
  }
}];

// Get current hospital to call from the list
const data = $input.first().json;
const currentIndex = data.currentHospitalIndex || 0;
const hospital = data.hospitals[currentIndex];

if (!hospital) {
  // No more hospitals to call
  return [{
    json: {
      ...data,
      noMoreHospitals: true
    }
  }];
}

return [{
  json: {
    ...data,
    currentHospital: hospital.name,
    currentPhone: hospital.phone,
    currentDistance: hospital.distance,
    currentAddress: hospital.address,
    noMoreHospitals: false
  }
}];

// Check if hospital answered the call
const callData = $('Call Hospital').first().json;
const webhookData = $input.first().json;
const originalData = $('Get Next Hospital to Call').first().json;

// Determine if call was answered
const callStatus = webhookData.CallStatus || callData.status || 'unknown';
const answeredStatuses = ['completed', 'in-progress', 'answered'];
const callAnswered = answeredStatuses.includes(callStatus);

const callSid = callData.sid || webhookData.CallSid || 'unknown';

return [{
  json: {
    ...originalData,
    callAnswered: callAnswered,
    callStatus: callStatus,
    callSid: callSid,
    attemptedHospital: originalData.currentHospital,
    attemptedPhone: originalData.currentPhone,
    attemptedDistance: originalData.currentDistance
  }
}];

const data = $input.first().json;

// Calculate ETA based on distance (assuming 40 km/h average speed)
const distance = parseFloat(data.attemptedDistance) || 5;
const etaMinutes = Math.ceil(distance / 40 * 60);

return [{
  json: {
    phoneNumber: data.phoneNumber,
    message: `✅ *AMBULANCE DISPATCHED!*\n\n` +
             `🏥 Hospital: ${data.attemptedHospital}\n` +
             `📞 Contact: ${data.attemptedPhone}\n` +
             `📍 Distance: ${data.attemptedDistance} km\n\n` +
             `🚑 Ambulance is on the way!\n` +
             `⏱️ Estimated arrival: ${etaMinutes} minutes\n\n` +
             `Stay calm. Help is coming!`
  }
}];

// Move to next hospital in the list
const data = $input.first().json;

return [{
  json: {
    ...data,
    currentHospitalIndex: data.currentHospitalIndex + 1,
    callAttempts: [...(data.callAttempts || []), {
      hospital: data.attemptedHospital,
      phone: data.attemptedPhone,
      status: 'no-answer'
    }]
  }
}];

const data = $input.first().json;
const topHospitals = data.hospitals.slice(0, 5);

const hospitalList = topHospitals.map((h, i) => 
  `${i+1}. *${h.name}*\n   📞 ${h.phone}\n   📍 ${h.distance} km`
).join('\n\n');

return [{
  json: {
    phoneNumber: data.phoneNumber,
    message: `⚠️ *Unable to reach hospitals by phone*\n\n` +
             `Please call directly:\n\n${hospitalList}\n\n` +
             `🚑 *Emergency Services:*\n` +
             `• Ambulance: 108\n` +
             `• Police: 100\n` +
             `• Fire: 101`
  }
}];

// Extract hospitals from Google Places API response
const places = $json.places || [];

// Get user data from HTTP Request node input (it has the location)
const inputData = $input.first().json;

// Default test data for testing (REMOVE IN PRODUCTION)
const userLat = inputData.latitude || 13.0826722;  // Test: Chennai
const userLon = inputData.longitude || 80.2006243;  // Test: Chennai
const phoneNumber = inputData.phoneNumber || '919876543210'; // Test phone
const userName = inputData.userName || 'User'; // Test name

if (!places || places.length === 0) {
  return [{
    json: {
      error: 'No hospitals found',
      phoneNumber: phoneNumber,
      userName: userName,
      latitude: userLat,
      longitude: userLon,
      noHospitals: true
    }
  }];
}

// Process and sort hospitals by distance
const hospitals = places.map(place => {
  const lat = place.location?.latitude || 0;
  const lon = place.location?.longitude || 0;

  // Calculate distance from user
  const R = 6371; // Earth radius in km
  const dLat = (lat - userLat) * Math.PI / 180;
  const dLon = (lon - userLon) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(userLat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  const distance = (R * c).toFixed(2);

  return {
    name: place.displayName?.text || 'Hospital',
    address: place.formattedAddress || 'Address not available',
    latitude: lat,
    longitude: lon,
    distance: distance,
    phone: null // Will be populated from database lookup
  };
}).sort((a, b) => parseFloat(a.distance) - parseFloat(b.distance));

// Create voice message for emergency call
const phoneSpoken = phoneNumber.split('').join(' ');
const voiceMessage = `This is an automated emergency alert. ` +
  `A patient has sent an S O S alert. ` +
  `Patient contact number is ${phoneSpoken}. ` +
  `Emergency location coordinates are ${userLat}, ${userLon}. ` +
  `This is a critical emergency. Please dispatch ambulance immediately. ` +
  `Press 1 to confirm ambulance dispatch.`;

return [{
  json: {
    hospitals: hospitals,
    hospitalCount: hospitals.length,
    phoneNumber: phoneNumber,
    userName: userName,
    latitude: userLat,
    longitude: userLon,
    voiceMessage: voiceMessage,
    currentHospitalIndex: 0,
    callAttempts: []
  }
}];

// Data from hospital processing
const data = $items('Process Hospital Data1')[0].json;
// Data from DB insert (Create a row)
const sosRow = $items('Create a row')[0].json;

// List of hospitals (we created this earlier in Process Hospital Data1)
const hospitals = data.hospitals || [];

// Create one item per hospital with all info needed for call
return hospitals.map(h => ({
  json: {
    // user info
    userName: data.userName || 'Patient',
    userPhone: data.phoneNumber,
    latitude: data.latitude,
    longitude: data.longitude,
    landmark: data.landmark,
    city: data.city,
    state: data.state,

    // DB info (optional)
    sosId: sosRow.id,

    // hospital info
    hospitalName: h.name,
    hospitalPhone: h.phone,
    hospitalDistance: h.distance,
    hospitalLat: h.lat,
    hospitalLon: h.lon,

    // voice message for Twilio
    voiceMessage:
      `This is an emergency SOS call. ` +
      `Patient ${data.userName || 'a user'} needs urgent help. ` +
      `Their phone number is ${data.phoneNumber}. ` +
      `They are near ${data.landmark}, ${data.city}, ${data.state}. ` +
      `Coordinates ${data.latitude}, ${data.longitude}. ` +
      `Your hospital ${h.name} is approximately ${h.distance} kilometers away. ` +
      `Please dispatch an ambulance immediately.`
  }
}));
